def main():
    print("=" * 70)
    print("Testing W4A8_MXFP4_INT8 Support Implementation")
    print("=" * 70)

    all_passed = []
    all_failed = []

    print("\n1. Testing Python Mode File")
    print("-" * 70)
    passed, failed = test_python_mode_file()
    for msg in passed:
        print(msg)
    for msg in failed:
        print(msg)
    all_passed.extend(passed)
    all_failed.extend(failed)

    print("\n2. Testing C++ Header File")
    print("-" * 70)
